cqiCfg_D             = cqiCfg;
cqiCfg_D.CodebookMode = 2;
[cqi_D_vec, ~, ~, pmiInfo_D] = nr5g.internal.nrCQISelect( ...
    carrier, csirs{1}, cqiCfg_D, ri_D, H_4d, nVar_wb);
cqi_D = cqi_D_vec(1);
