140	\subsection{Cấu trúc bộ tiền mã hoá Mode B (Bảng 5.2.2.2.1a-7)}
141	
142	Cho hạng $v$ ($v = 1,2,3,4$), bộ tiền mã hoá là:
143	\begin{equation}
144	  W^{(v)} = \frac{1}{\sqrt{v \cdot P}}
145	  \underbrace{\begin{bmatrix}
146	    \mathbf{V}_{\text{top}} \\
147	    \boldsymbol{\Phi}\,\mathbf{V}_{\text{top}}
148	  \end{bmatrix}}_{P \times v}, \quad
149	  \mathbf{V}_{\text{top}} =
150	  \bigl[v_{m_1^{(1)},m_2^{(1)}},\,\ldots,\,v_{m_1^{(v)},m_2^{(v)}}\bigr],
151	  \quad
152	  \boldsymbol{\Phi} = \mathrm{diag}\bigl(\varphi(c_1),\ldots,\varphi(c_v)\bigr)
153	  \label{eq:W_modeB}
154	\end{equation}
155	
156	\noindent\textbf{Kiểm tra chuẩn hoá}:
157	\begin{equation}
158	  \|W^{(v)}\|_F^2 = \frac{1}{v P} \cdot
159	  \bigl(\|\mathbf{V}_{\text{top}}\|_F^2 + \|\boldsymbol{\Phi}\,\mathbf{V}_{\text{top}}\|_F^2\bigr)
160	  = \frac{1}{vP} \cdot 2 \sum_{l=1}^{v} \|v_{m_1^{(l)},m_2^{(l)}}\|^2
161	  = \frac{1}{vP} \cdot 2vP/2 = 1
162	  \label{eq:norm_check}
163	\end{equation}
164	vì mỗi $\|v_{l,m}\|^2 = N_1 N_2 = P/2$.
165	
166	\subsection{Lưới DFT Mode B bao phủ cùng không gian với Mode A}
167	
168	Nhận xét quan trọng: với hạng~1, không gian tìm kiếm Mode~B
169	\emph{bao trùm chính xác} không gian của Mode~A.
170	Mỗi cặp $(q_1, q_2) \in \{0,\ldots,O_1{-}1\}\times\{0,\ldots,O_2{-}1\}$
171	tạo ra một lưới con $\{m_1 = O_1 n_1 + q_1\} \times \{m_2 = O_2 n_2 + q_2\}$,
172	và hợp của $O_1 O_2 = 16$ lưới con đó chính là toàn bộ lưới
173	$\{0,\ldots,N_1 O_1{-}1\} \times \{0,\ldots,N_2 O_2{-}1\}$ mà Mode~A sử dụng.
174	Điều này đảm bảo:
175	\begin{equation}
176	  \text{cap}(W^{(1)}_\text{ModeB}) = \text{cap}(W^{(1)}_\text{ModeA})
177	  \quad \text{(hạng 1, khi tìm kiếm đầy đủ)}
178	  \label{eq:equiv_rank1}
179	\end{equation}
