182	\section{Thách thức Kỹ thuật và Phân tích Thiết kế}
183	%% ============================================================
184	
185	\subsection{Vấn đề Kích thước Codebook}
186	
187	Với Mode~A, codebook được \emph{tính trước} (precomputed) dưới dạng tensor
188	$\mathbf{C} \in \mathbb{C}^{P \times v \times N_{i_2} \times N_{i_{1,1}} \times N_{i_{1,2}} \times N_{i_{1,3}}}$
189	rồi truyền vào hàm tìm PMI. Cách tiếp cận này không áp dụng được cho Mode~B
190	vì số ứng viên codebook tăng theo lũy thừa với hạng:
191	
192	\begin{table}[H]
193	\centering
194	\caption{Kích thước không gian tìm kiếm Mode B}
195	\begin{tabular}{ccccc}
196	\toprule
197	Hạng $v$ & $O_1 O_2$ & $N_1 N_2$ (beam/tầng) & $4^v$ (co-phase) & Tổng ứng viên \\
198	\midrule
199	1 & 16 & 64 & 4 & 4\,096 \\
200	2 & 16 & $64^2 = 4{,}096$ & 16 & 1\,048\,576 \\
201	3 & 16 & $64^3 = 262{,}144$ & 64 & $\approx 2{,}7 \times 10^8$ \\
202	4 & 16 & $64^4 = 16{,}777{,}216$ & 256 & $\approx 6{,}9 \times 10^{10}$ \\
203	\midrule
204	\multicolumn{4}{l}{Bộ nhớ tensor hạng 2 (complex128)} & $\approx 4{,}3$~GB \\
205	\bottomrule
206	\end{tabular}
207	\end{table}
208	
209	\noindent Hạng~2 đã yêu cầu 4,3~GB RAM --- \textbf{không khả thi} để tính trước.
210	Do đó cần thiết kế thuật toán tìm kiếm trực tuyến.
211	
212	\subsection{Chiến lược: Greedy Factored Search}
213	
214	Thay vì tìm kiếm vét cạn toàn bộ không gian, thuật toán được chia thành
215	ba giai đoạn phân cấp:
216	
217	\begin{tcolorbox}[colback=blue!5,colframe=blue!50,title=Greedy Factored Search --- Ba giai đoạn]
218	\begin{description}[leftmargin=2em]
219	  \item[Giai đoạn 1:] Liệt kê $O_1 O_2 = 16$ cặp offset $(q_1, q_2)$.
220	  \item[Giai đoạn 2:] Với mỗi $(q_1, q_2)$:
221	    \begin{itemize}
222	      \item \textbf{Hạng 1}: duyệt tất cả $N_1 N_2 = 64$ beam (vét cạn hoàn toàn).
223	      \item \textbf{Hạng $v > 1$}: dùng SVD wideband $\mathbf{H}_\text{wb}$ để chọn 1 beam tốt nhất
224	            cho mỗi tầng (greedy, phức tạp tuyến tính).
225	    \end{itemize}
226	  \item[Giai đoạn 3:] Duyệt vét cạn $4^v$ tổ hợp co-phase cho bộ beam đã chọn;
227	        chọn $W$ tối đa hoá dung lượng Shannon $\log_2\det(\mathbf{I} + \frac{1}{\sigma^2}\mathbf{H}_\text{wb}\mathbf{W}\mathbf{W}^H\mathbf{H}_\text{wb}^H)$.
228	\end{description}
229	\end{tcolorbox}
230	
231	\medskip
232	\noindent\textbf{Độ phức tạp so sánh}:
233	\begin{itemize}
234	  \item Hạng 1: $16 \times 64 \times 4 = 4{,}096$ đánh giá (bằng Mode~A, đảm bảo tối ưu).
235	  \item Hạng 2: $16 \times (64 + 16) = 1{,}280$ đánh giá tổng (so với $> 10^6$ vét cạn).
236	  \item Hạng 4: $16 \times (64 + 256) = 5{,}120$ đánh giá tổng.
237	\end{itemize}
238	
239	\subsection{Vấn đề Chọn Beam bằng SVD: Cả hai phân cực}
240	
241	Trong cài đặt ban đầu, việc chấm điểm beam cho hạng $v > 1$ dùng hình chiếu lên
242	\emph{nửa trên} của vector kỳ dị phải:
243	\begin{equation}
244	  \text{score}(n,l)_\text{sai} = |V_q^H \mathbf{V}_\text{top}|_{n,l}^2
245	  \quad \text{(chỉ phân cực trên)}
246	\end{equation}
247	Điều này bỏ qua phân cực dưới. Với kênh Rayleigh ngẫu nhiên, $\mathbf{H}_\text{top}$
248	và $\mathbf{H}_\text{bot}$ độc lập nên vector kỳ dị $\mathbf{v}_l \in \mathbb{C}^{2N_1N_2}$
249	phân bổ năng lượng đồng đều giữa hai nửa. Hình chiếu chỉ lên nửa trên
250	bỏ mất $\approx 50\%$ thông tin.
251	
252	\medskip\noindent\textbf{Sửa chữa}: dùng tổng đóng góp của cả hai phân cực:
253	\begin{equation}
254	  \text{score}(n,l)_\text{đúng} =
255	  \underbrace{|V_q^H \mathbf{V}_\text{top}|_{n,l}^2}_{\text{phân cực trên}}
256	  + \underbrace{|V_q^H \mathbf{V}_\text{bot}|_{n,l}^2}_{\text{phân cực dưới}}
257	  \label{eq:score_both}
258	\end{equation}
259	với $\mathbf{V}_\text{top} = \mathbf{V}_\text{svd}(1:N_1N_2,\,:)$ và
260	$\mathbf{V}_\text{bot} = \mathbf{V}_\text{svd}(N_1N_2{+}1:\text{end},\,:)$.
