\midrule
\multicolumn{4}{l}{Bộ nhớ tensor hạng 2 (complex128)} & $\approx 4{,}3$~GB \\
\bottomrule
\end{tabular}
\end{table}

\noindent Hạng~2 đã yêu cầu 4,3~GB RAM --- \textbf{không khả thi} để tính trước.
