387	\subsubsection{Giao diện hàm}
388	
389	\begin{lstlisting}
390	function [W, pmiModeB, sinrOut] = getPMIType1SinglePanelR19CodebookModeB(...
391	    Hcsirs, reportConfig, nLayers, nVar, Pcsirs)
392	% Inputs:
393	%   Hcsirs   [nRx x Pcsirs x nRE] - Channel tại CSI-RS RE locations
394	%   nLayers  scalar                - Rank (1..4)
395	%   nVar     scalar                - Noise variance (wideband average)
396	%   Pcsirs   scalar                - Số port CSI-RS (= 128)
397	% Outputs:
398	%   W        [Pcsirs x nLayers]   - Ma trận tiền mã hoá tối ưu
399	%   pmiModeB struct                - {q1, q2, n_idx[1..v], c_idx[1..v]}
400	%   sinrOut  [nLayers x 1]        - SINR per-layer (ZF, linear)
401	\end{lstlisting}
402	
403	\subsubsection{Bước 1: Trung bình Wideband và SVD}
404	
405	\begin{lstlisting}
406	% Wideband channel: average over RE dimension
407	H_wb = mean(Hcsirs, 3);   % [nRx x Pcsirs]
408	
409	% SVD: leading nLayers right singular vectors
410	[~, ~, V] = svd(H_wb, 'econ');
411	V_svd = V(:, 1:nLayers);          % [Pcsirs x nLayers]
412	V_top = V_svd(1:n_len, :);        % [N1N2 x nLayers]  - phân cực trên
413	V_bot = V_svd(n_len+1:end, :);    % [N1N2 x nLayers]  - phân cực dưới
414	\end{lstlisting}
415	
416	\noindent Vector kỳ dị phải $\mathbf{v}_l$ (cột $l$ của $\mathbf{V}$) nằm trong
417	không gian hàng của $\mathbf{H}_\text{wb}$ và biểu diễn hướng phát tối ưu cho
418	tầng $l$. Thuật toán sẽ tìm beam DFT gần nhất với $\mathbf{v}_l$.
419	
420	\subsubsection{Bước 2: Xây dựng ma trận DFT cho từng offset $(q_1, q_2)$}
421	
422	\begin{lstlisting}
423	for q_idx = 0:q_len-1    % q_len = O1*O2 = 16
424	    q1 = floor(q_idx / O2);
425	    q2 = mod(q_idx, O2);
426	
427	    % V_q: [N1N2 x N1N2], cột n = v_{m1,m2} với offset (q1,q2)
428	    V_q = zeros(n_len, n_len);
429	    for n_idx = 0:n_len-1
430	        n_val = N1*N2 - 1 - n_idx;            % Phuong trinh (2)
431	        n1    = mod(n_val, N1);
432	        n2    = (n_val - n1) / N1;
433	        m1    = O1*n1 + q1;                    % Phuong trinh (4)
434	        m2    = O2*n2 + q2;
435	        V_q(:, n_idx+1) = getVlm(N1,N2,O1,O2,m1,m2);
436	    end
437	    ...
438	end
439	\end{lstlisting}
440	
441	\noindent Ma trận $\mathbf{V}_q \in \mathbb{C}^{N_1 N_2 \times N_1 N_2}$ là
442	ma trận DFT 2D đã oversampling cho lưới con thứ $q$. Mỗi cột là một ứng viên beam.
443	
444	\subsubsection{Bước 3: Chọn beam ứng viên}
445	
446	\begin{lstlisting}
447	if nLayers == 1
448	    % Hang 1: vet can tat ca N1*N2 beam (khong gian = Mode A)
449	    n_cand_matrix = (0:n_len-1)';  % [64 x 1]
450	else
451	    % Hang > 1: greedy top-1 beam/tang tu diem chieu ca 2 phan cuc
452	    scores = abs(V_q' * V_top).^2 + abs(V_q' * V_bot).^2; % [64 x nLayers]
453	    n_cand = zeros(1, nLayers);
454	    for l = 1:nLayers
455	        [~, n_cand(l)] = max(scores(:, l));
456	        n_cand(l) = n_cand(l) - 1;    % 0-based
457	    end
458	    n_cand_matrix = n_cand;  % [1 x nLayers]
459	end
460	\end{lstlisting}
461	
462	\noindent\textbf{Giải thích điểm số} \eqref{eq:score_both}: với beam $v_n$ và
463	tầng $l$, điểm số đo lường năng lượng kênh được ghi nhận bởi beam $v_n$
464	khi kết hợp cả hai phân cực anten gNB. Việc thiếu $\mathbf{V}_\text{bot}$
465	gây chọn beam sai trong $\approx 85\%$ trường hợp trên kênh Rayleigh.
466	
467	\subsubsection{Bước 4: Tìm kiếm co-phase vét cạn}
468	
469	\begin{lstlisting}
470	% Co-phase: 4^nLayers combinations (max 256 for rank 4)
471	c_combos = dec2base(0:4^nLayers-1, 4, nLayers) - '0';  % [4^v x v]
472	
473	for n_row = 1:size(n_cand_matrix,1)
474	    n_try = n_cand_matrix(n_row);  % beam index
475	
476	    for ci = 1:size(c_combos,1)
477	        c_vec = c_combos(ci,:);    % [1 x nLayers]
478	
479	        % Assemble W theo Phuong trinh (1)
480	        W_top_c = zeros(n_len, nLayers);
481	        W_bot_c = zeros(n_len, nLayers);
482	        for l = 1:nLayers
483	            nb    = n_try(min(l, numel(n_try)));
484	            n_val = N1*N2 - 1 - nb;
485	            n1    = mod(n_val, N1);  n2 = (n_val-n1)/N1;
486	            m1    = O1*n1 + q1;      m2 = O2*n2 + q2;
