\toprule
 & \textbf{Mode A (\texttt{CodebookMode=1})} & \textbf{Mode B (\texttt{CodebookMode=2})} \\
\midrule
Chỉ số beam & $l \in [0,N_1O_1{-}1]$, $m \in [0,N_2O_2{-}1]$ (chung) & $(q_1,q_2)$ offset + $i_{1,2,l}$ per-layer \\
